from collections import defaultdict


class DetectSquares:
    def __init__(self):
        self.pts = defaultdict(int)  # (x,y) -> count

    def add(self, point):
        self.pts[(point[0], point[1])] += 1

    def count(self, point):
        qx, qy = point[0], point[1]
        total = 0
        # brute-force: enumerate all pairs of stored points as potential diagonals
        all_pts = list(self.pts.keys())
        for (x1, y1), c1 in list(self.pts.items()):
            for (x2, y2), c2 in list(self.pts.items()):
                # (qx,qy), (x1,y1), (x2,y2), fourth corner forms an axis-aligned square
                # need: x2==qx, y1==qy, x1!=qx (side length != 0)
                if x2 == qx and y1 == qy and abs(x1 - qx) == abs(y2 - qy) and x1 != qx:
                    fourth_count = self.pts.get((x1, y2), 0)
                    total += c1 * c2 * fourth_count
        return total

