class DetectSquares {
    constructor() {
        this.ptCount = new Map();
        this.xToYs = new Map();
    }
    _key(x, y) { return x * 1001 + y; }
    add(point) {
        const [x, y] = point;
        const k = this._key(x, y);
        this.ptCount.set(k, (this.ptCount.get(k) || 0) + 1);
        if (!this.xToYs.has(x)) this.xToYs.set(x, new Set());
        this.xToYs.get(x).add(y);
    }
    count(point) {
        const [qx, qy] = point;
        let total = 0;
        const ys = this.xToYs.get(qx);
        if (!ys) return 0;
        for (const y3 of ys) {
            if (y3 === qy) continue;
            const side = Math.abs(y3 - qy);
            for (const dx of [side, -side]) {
                const x3 = qx + dx;
                const c1 = this.ptCount.get(this._key(qx, y3)) || 0;
                const c2 = this.ptCount.get(this._key(x3, qy)) || 0;
                const c3 = this.ptCount.get(this._key(x3, y3)) || 0;
                total += c1 * c2 * c3;
            }
        }
        return total;
    }
}
